import type { VercelRequest, VercelResponse } from "@vercel/node";
import { createHmac } from "crypto";
import { Pool } from "pg";

let pool: Pool | null = null;
function getPool(): Pool {
  if (!pool) pool = new Pool({ connectionString: process.env.DATABASE_URL, ssl: { rejectUnauthorized: false } });
  return pool;
}

function verifyToken(token: string, secret: string): boolean {
  try {
    const [payload, sig] = token.split(".");
    if (!payload || !sig) return false;
    const expected = createHmac("sha256", secret).update(payload).digest("base64url");
    if (sig !== expected) return false;
    const { exp } = JSON.parse(Buffer.from(payload, "base64url").toString());
    return typeof exp === "number" && exp > Date.now();
  } catch { return false; }
}

function getTokenFromCookies(cookieHeader: string): string | null {
  for (const part of cookieHeader.split(";")) {
    const [k, v] = part.trim().split("=");
    if (k.trim() === "admin_token" && v) return v;
  }
  return null;
}

export default async function handler(req: VercelRequest, res: VercelResponse) {
  const JWT_SECRET = process.env.ADMIN_JWT_SECRET;
  if (!JWT_SECRET) return res.status(500).json({ error: "Not configured" });
  const token = getTokenFromCookies(req.headers.cookie ?? "");
  if (!token || !verifyToken(token, JWT_SECRET)) return res.status(401).json({ error: "Unauthorized" });

  const db = getPool();

  // Ensure table exists
  await db.query(`
    CREATE TABLE IF NOT EXISTS leads (
      id SERIAL PRIMARY KEY,
      email TEXT NOT NULL,
      score INTEGER NOT NULL,
      category TEXT,
      created_at TIMESTAMPTZ DEFAULT NOW()
    )
  `);

  if (req.method === "GET") {
    const { rows } = await db.query(`
      SELECT id, email, score, category, created_at
      FROM leads
      ORDER BY created_at DESC
      LIMIT 100
    `);

    const stats = await db.query(`
      SELECT
        COUNT(*)::int AS total,
        ROUND(AVG(score))::int AS avg_score,
        COUNT(*) FILTER (WHERE created_at > NOW() - INTERVAL '7 days')::int AS last_7_days,
        COUNT(*) FILTER (WHERE created_at > NOW() - INTERVAL '30 days')::int AS last_30_days
      FROM leads
    `);

    return res.status(200).json({ leads: rows, stats: stats.rows[0] });
  }

  return res.status(405).end();
}

import type { VercelRequest, VercelResponse } from "@vercel/node";
import { createHmac } from "crypto";
import { Pool } from "pg";

function verifyToken(token: string, secret: string): boolean {
  try {
    const [payload, sig] = token.split(".");
    if (!payload || !sig) return false;
    const expected = createHmac("sha256", secret).update(payload).digest("base64url");
    if (sig !== expected) return false;
    const { exp } = JSON.parse(Buffer.from(payload, "base64url").toString());
    return typeof exp === "number" && exp > Date.now();
  } catch { return false; }
}

function getTokenFromCookies(cookieHeader: string): string | null {
  for (const part of cookieHeader.split(";")) {
    const [k, v] = part.trim().split("=");
    if (k.trim() === "admin_token" && v) return v;
  }
  return null;
}

interface ServiceCheck {
  name: string;
  status: "ok" | "warn" | "error";
  message: string;
}

export default async function handler(req: VercelRequest, res: VercelResponse) {
  const JWT_SECRET = process.env.ADMIN_JWT_SECRET;
  if (!JWT_SECRET) return res.status(500).json({ error: "Not configured" });
  const token = getTokenFromCookies(req.headers.cookie ?? "");
  if (!token || !verifyToken(token, JWT_SECRET)) return res.status(401).json({ error: "Unauthorized" });

  const checks: ServiceCheck[] = [];

  // Database
  try {
    const pool = new Pool({ connectionString: process.env.DATABASE_URL, ssl: { rejectUnauthorized: false } });
    await pool.query("SELECT 1");
    await pool.end();
    checks.push({ name: "Base de datos (Neon)", status: "ok", message: "Conexión correcta" });
  } catch {
    checks.push({ name: "Base de datos (Neon)", status: "error", message: "Sin conexión — verifica DATABASE_URL" });
  }

  // Resend API Key
  if (process.env.RESEND_API_KEY) {
    checks.push({ name: "Resend API Key", status: "ok", message: "Configurada" });
  } else {
    checks.push({ name: "Resend API Key", status: "error", message: "No configurada — los emails del quiz no se enviarán" });
  }

  // Resend Audience ID
  if (process.env.RESEND_AUDIENCE_ID) {
    checks.push({ name: "Resend Audience ID", status: "ok", message: "Configurado — leads guardándose en Resend" });
  } else {
    checks.push({ name: "Resend Audience ID", status: "warn", message: "No configurado — leads no se guardan en Resend" });
  }

  // Admin JWT Secret
  checks.push({ name: "Admin JWT Secret", status: "ok", message: "Configurado" });

  // Admin Password
  if (process.env.ADMIN_PASSWORD) {
    checks.push({ name: "Contraseña de Admin", status: "ok", message: "Configurada" });
  } else {
    checks.push({ name: "Contraseña de Admin", status: "error", message: "No configurada" });
  }

  // Calendly URL (client-side env, check VITE_ prefix)
  // Note: VITE_ vars are not available server-side, so we can't check directly
  checks.push({ name: "Calendly URL (VITE_CALENDLY_URL)", status: "warn", message: "No verificable desde servidor — comprueba en Vercel Settings" });

  const allOk = checks.every(c => c.status !== "error");
  return res.status(200).json({ healthy: allOk, checks });
}

import type { VercelRequest, VercelResponse } from "@vercel/node";
import { createHmac } from "crypto";
import { Pool } from "pg";

let pool: Pool | null = null;
function getPool(): Pool {
  if (!pool) pool = new Pool({ connectionString: process.env.DATABASE_URL, ssl: { rejectUnauthorized: false } });
  return pool;
}

function verifyToken(token: string, secret: string): boolean {
  try {
    const [payload, sig] = token.split(".");
    if (!payload || !sig) return false;
    const expected = createHmac("sha256", secret).update(payload).digest("base64url");
    if (sig !== expected) return false;
    const { exp } = JSON.parse(Buffer.from(payload, "base64url").toString());
    return typeof exp === "number" && exp > Date.now();
  } catch { return false; }
}

function getTokenFromCookies(cookieHeader: string): string | null {
  for (const part of cookieHeader.split(";")) {
    const [k, v] = part.trim().split("=");
    if (k.trim() === "admin_token" && v) return v;
  }
  return null;
}

async function ensureTable(db: Pool) {
  await db.query(`CREATE TABLE IF NOT EXISTS site_config (key TEXT PRIMARY KEY, value TEXT NOT NULL)`);
}

export default async function handler(req: VercelRequest, res: VercelResponse) {
  const JWT_SECRET = process.env.ADMIN_JWT_SECRET;
  if (!JWT_SECRET) return res.status(500).json({ error: "Not configured" });
  const token = getTokenFromCookies(req.headers.cookie ?? "");
  if (!token || !verifyToken(token, JWT_SECRET)) return res.status(401).json({ error: "Unauthorized" });

  const db = getPool();
  await ensureTable(db);

  if (req.method === "GET") {
    const { rows } = await db.query(`SELECT key, value FROM site_config WHERE key LIKE 'banner%' OR key = 'maintenance'`);
    const config: Record<string, string> = {};
    for (const row of rows) config[row.key] = row.value;
    return res.status(200).json({
      bannerEnabled: config["banner_enabled"] === "true",
      bannerText: config["banner_text"] ?? "",
      bannerType: (config["banner_type"] as "info" | "warning" | "success") ?? "info",
    });
  }

  if (req.method === "POST") {
    const { bannerEnabled, bannerText, bannerType } = req.body ?? {};

    const upsert = async (key: string, value: string) => {
      await db.query(`INSERT INTO site_config (key, value) VALUES ($1, $2) ON CONFLICT (key) DO UPDATE SET value = $2`, [key, value]);
    };

    if (typeof bannerEnabled === "boolean") await upsert("banner_enabled", String(bannerEnabled));
    if (typeof bannerText === "string") await upsert("banner_text", bannerText.slice(0, 200));
    if (typeof bannerType === "string" && ["info", "warning", "success"].includes(bannerType)) await upsert("banner_type", bannerType);

    return res.status(200).json({ ok: true });
  }

  return res.status(405).end();
}

import type { VercelRequest, VercelResponse } from "@vercel/node";
import { Pool } from "pg";

let pool: Pool | null = null;

export default async function handler(_req: VercelRequest, res: VercelResponse) {
  res.setHeader("Cache-Control", "no-store");
  try {
    if (!pool) pool = new Pool({ connectionString: process.env.DATABASE_URL, ssl: { rejectUnauthorized: false } });
    const { rows } = await pool.query(`SELECT key, value FROM site_config WHERE key LIKE 'banner%'`);
    const config: Record<string, string> = {};
    for (const row of rows) config[row.key] = row.value;
    return res.status(200).json({
      enabled: config["banner_enabled"] === "true",
      text: config["banner_text"] ?? "",
      type: config["banner_type"] ?? "info",
    });
  } catch {
    return res.status(200).json({ enabled: false, text: "", type: "info" });
  }
}

