import { useState, useEffect, useCallback } from "react";
import {
  Shield,
  LogOut,
  Power,
  AlertTriangle,
  CheckCircle,
  Loader2,
  Eye,
  EyeOff,
  LayoutDashboard,
  Users,
  Activity,
  Settings,
  RefreshCw,
} from "lucide-react";

// ── Types ─────────────────────────────────────────────────────────────────────
interface Lead {
  id: number;
  email: string;
  score: number;
  category: string | null;
  created_at: string;
}

interface LeadStats {
  total: number;
  avg_score: number;
  last_7_days: number;
  last_30_days: number;
}

interface ServiceCheck {
  name: string;
  status: "ok" | "warn" | "error";
  message: string;
}

interface BannerConfig {
  bannerEnabled: boolean;
  bannerText: string;
  bannerType: "info" | "warning" | "success";
}

type TabId = "inicio" | "leads" | "salud" | "config";

// ── Login Form ────────────────────────────────────────────────────────────────
function LoginForm({ onLogin }: { onLogin: () => void }) {
  const [password, setPassword] = useState("");
  const [showPw, setShowPw] = useState(false);
  const [error, setError] = useState("");
  const [loading, setLoading] = useState(false);

  async function handleSubmit(e: React.FormEvent) {
    e.preventDefault();
    setError("");
    setLoading(true);
    try {
      const res = await fetch("/api/admin/login", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ password }),
        credentials: "include",
      });
      if (res.ok) {
        onLogin();
      } else {
        const data = await res.json() as { error?: string };
        setError(data.error ?? "Contraseña incorrecta");
      }
    } catch {
      setError("Error de conexión");
    } finally {
      setLoading(false);
    }
  }

  return (
    <div className="min-h-screen bg-[#0F2438] flex items-center justify-center p-4">
      <div className="w-full max-w-sm">
        <div className="flex flex-col items-center mb-8 gap-3">
          <div className="w-16 h-16 rounded-full bg-[#FFD400]/10 border border-[#FFD400]/30 flex items-center justify-center">
            <Shield className="w-8 h-8 text-[#FFD400]" />
          </div>
          <h1 className="text-xl font-black text-white">Panel de Administración</h1>
          <p className="text-slate-400 text-sm">techbyflo.com</p>
        </div>

        <form onSubmit={handleSubmit} className="space-y-4">
          <div className="relative">
            <input
              type={showPw ? "text" : "password"}
              value={password}
              onChange={(e) => setPassword(e.target.value)}
              placeholder="Contraseña de administrador"
              className="w-full bg-slate-800/60 border border-slate-700 rounded-xl px-4 py-3 text-white placeholder-slate-500 focus:outline-none focus:border-[#FFD400]/50 pr-12"
              required
              autoFocus
            />
            <button
              type="button"
              onClick={() => setShowPw(!showPw)}
              className="absolute right-3 top-1/2 -translate-y-1/2 text-slate-400 hover:text-white"
            >
              {showPw ? <EyeOff className="w-4 h-4" /> : <Eye className="w-4 h-4" />}
            </button>
          </div>

          {error && (
            <div className="flex items-center gap-2 text-red-400 text-sm bg-red-400/10 border border-red-400/20 rounded-lg px-3 py-2">
              <AlertTriangle className="w-4 h-4 flex-shrink-0" />
              {error}
            </div>
          )}

          <button
            type="submit"
            disabled={loading || !password}
            className="w-full bg-[#FFD400] hover:bg-[#FFE033] disabled:opacity-50 text-[#0F2438] font-black py-3 px-6 rounded-xl transition-all flex items-center justify-center gap-2"
          >
            {loading ? <Loader2 className="w-4 h-4 animate-spin" /> : "Entrar"}
          </button>
        </form>
      </div>
    </div>
  );
}

// ── Stat Card ─────────────────────────────────────────────────────────────────
function StatCard({ label, value, loading }: { label: string; value: string | number; loading: boolean }) {
  return (
    <div className="bg-slate-800/40 border border-slate-700 rounded-2xl p-5">
      <p className="text-slate-400 text-xs uppercase tracking-wide mb-1">{label}</p>
      {loading ? (
        <div className="h-8 w-16 bg-slate-700 rounded animate-pulse" />
      ) : (
        <p className="text-white text-2xl font-black">{value}</p>
      )}
    </div>
  );
}

// ── Category Badge ────────────────────────────────────────────────────────────
function CategoryBadge({ category, score }: { category: string | null; score: number }) {
  const label = category ?? getCategoryLabel(score);
  const colorClass =
    score >= 81 ? "bg-green-500/20 text-green-300 border-green-500/30" :
    score >= 61 ? "bg-blue-500/20 text-blue-300 border-blue-500/30" :
    score >= 41 ? "bg-yellow-500/20 text-yellow-300 border-yellow-500/30" :
    score >= 21 ? "bg-orange-500/20 text-orange-300 border-orange-500/30" :
                  "bg-red-500/20 text-red-300 border-red-500/30";

  return (
    <span className={`inline-flex items-center px-2 py-0.5 rounded-full text-xs font-semibold border ${colorClass}`}>
      {label}
    </span>
  );
}

function getCategoryLabel(score: number): string {
  if (score >= 81) return "Blindado";
  if (score >= 61) return "Protegido";
  if (score >= 41) return "En Riesgo";
  if (score >= 21) return "Vulnerable";
  return "Crítico";
}

// ── Tab: Inicio ───────────────────────────────────────────────────────────────
function TabInicio() {
  const [stats, setStats] = useState<LeadStats | null>(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    fetch("/api/admin/leads", { credentials: "include" })
      .then((r) => r.json())
      .then((d: { stats?: LeadStats }) => setStats(d.stats ?? null))
      .catch(() => setStats(null))
      .finally(() => setLoading(false));
  }, []);

  return (
    <div className="space-y-4">
      <h2 className="text-white font-bold text-lg">Resumen</h2>
      <div className="grid grid-cols-2 gap-3">
        <StatCard label="Total Leads" value={stats?.total ?? 0} loading={loading} />
        <StatCard label="Leads 7 días" value={stats?.last_7_days ?? 0} loading={loading} />
        <StatCard label="Leads 30 días" value={stats?.last_30_days ?? 0} loading={loading} />
        <StatCard label="Score Promedio" value={stats?.avg_score != null ? `${stats.avg_score}/100` : "—"} loading={loading} />
      </div>
    </div>
  );
}

// ── Tab: Leads ────────────────────────────────────────────────────────────────
function TabLeads() {
  const [leads, setLeads] = useState<Lead[]>([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    fetch("/api/admin/leads", { credentials: "include" })
      .then((r) => r.json())
      .then((d: { leads?: Lead[] }) => setLeads(d.leads ?? []))
      .catch(() => setLeads([]))
      .finally(() => setLoading(false));
  }, []);

  if (loading) {
    return (
      <div className="space-y-2">
        {[...Array(5)].map((_, i) => (
          <div key={i} className="h-12 bg-slate-800/40 rounded-xl animate-pulse" />
        ))}
      </div>
    );
  }

  if (leads.length === 0) {
    return (
      <div className="text-center py-12">
        <Users className="w-10 h-10 text-slate-600 mx-auto mb-3" />
        <p className="text-slate-400 text-sm">No hay leads todavía.</p>
        <p className="text-slate-600 text-xs mt-1">Aparecerán aquí cuando alguien complete el quiz.</p>
      </div>
    );
  }

  return (
    <div className="space-y-3">
      <h2 className="text-white font-bold text-lg">Leads ({leads.length})</h2>
      <div className="overflow-x-auto">
        <table className="w-full text-sm">
          <thead>
            <tr className="text-slate-400 text-xs uppercase tracking-wide border-b border-slate-700">
              <th className="text-left pb-2 pr-3">Email</th>
              <th className="text-left pb-2 pr-3">Score</th>
              <th className="text-left pb-2 pr-3">Categoría</th>
              <th className="text-left pb-2">Fecha</th>
            </tr>
          </thead>
          <tbody>
            {leads.map((lead) => (
              <tr key={lead.id} className="border-b border-slate-800 hover:bg-slate-800/20 transition-colors">
                <td className="py-2.5 pr-3 text-white text-xs truncate max-w-[160px]">{lead.email}</td>
                <td className="py-2.5 pr-3 text-slate-300 font-mono">{lead.score}</td>
                <td className="py-2.5 pr-3">
                  <CategoryBadge category={lead.category} score={lead.score} />
                </td>
                <td className="py-2.5 text-slate-500 text-xs whitespace-nowrap">
                  {new Date(lead.created_at).toLocaleDateString("es-ES", { day: "2-digit", month: "short", year: "2-digit" })}
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </div>
  );
}

// ── Tab: Salud ────────────────────────────────────────────────────────────────
function TabSalud() {
  const [checks, setChecks] = useState<ServiceCheck[]>([]);
  const [healthy, setHealthy] = useState<boolean | null>(null);
  const [loading, setLoading] = useState(true);

  const fetchHealth = useCallback(() => {
    setLoading(true);
    fetch("/api/admin/health", { credentials: "include" })
      .then((r) => r.json())
      .then((d: { healthy?: boolean; checks?: ServiceCheck[] }) => {
        setHealthy(d.healthy ?? false);
        setChecks(d.checks ?? []);
      })
      .catch(() => {
        setHealthy(false);
        setChecks([]);
      })
      .finally(() => setLoading(false));
  }, []);

  useEffect(() => { fetchHealth(); }, [fetchHealth]);

  const dotColor = (status: ServiceCheck["status"]) => {
    if (status === "ok") return "bg-green-400";
    if (status === "warn") return "bg-yellow-400";
    return "bg-red-400";
  };

  return (
    <div className="space-y-4">
      <div className="flex items-center justify-between">
        <h2 className="text-white font-bold text-lg">
          Estado de Servicios
          {healthy !== null && (
            <span className={`ml-2 text-xs font-normal px-2 py-0.5 rounded-full ${healthy ? "bg-green-500/20 text-green-300" : "bg-red-500/20 text-red-300"}`}>
              {healthy ? "Todo OK" : "Hay errores"}
            </span>
          )}
        </h2>
        <button
          onClick={fetchHealth}
          disabled={loading}
          className="flex items-center gap-1.5 text-slate-400 hover:text-white text-sm transition-colors disabled:opacity-50"
        >
          <RefreshCw className={`w-4 h-4 ${loading ? "animate-spin" : ""}`} />
          Verificar ahora
        </button>
      </div>

      {loading ? (
        <div className="space-y-2">
          {[...Array(6)].map((_, i) => (
            <div key={i} className="h-14 bg-slate-800/40 rounded-xl animate-pulse" />
          ))}
        </div>
      ) : (
        <div className="space-y-2">
          {checks.map((check) => (
            <div key={check.name} className="bg-slate-800/40 border border-slate-700 rounded-xl px-4 py-3 flex items-start gap-3">
              <span className={`mt-1.5 w-2 h-2 rounded-full flex-shrink-0 ${dotColor(check.status)}`} />
              <div>
                <p className="text-white text-sm font-medium">{check.name}</p>
                <p className="text-slate-400 text-xs mt-0.5">{check.message}</p>
              </div>
            </div>
          ))}
        </div>
      )}
    </div>
  );
}

// ── Tab: Config ───────────────────────────────────────────────────────────────
function TabConfig() {
  const [config, setConfig] = useState<BannerConfig>({ bannerEnabled: false, bannerText: "", bannerType: "info" });
  const [loading, setLoading] = useState(true);
  const [saving, setSaving] = useState(false);
  const [saved, setSaved] = useState(false);
  const [error, setError] = useState("");

  useEffect(() => {
    fetch("/api/admin/config", { credentials: "include" })
      .then((r) => r.json())
      .then((d: Partial<BannerConfig>) => setConfig({
        bannerEnabled: d.bannerEnabled ?? false,
        bannerText: d.bannerText ?? "",
        bannerType: d.bannerType ?? "info",
      }))
      .catch(() => {})
      .finally(() => setLoading(false));
  }, []);

  async function handleSave() {
    setSaving(true);
    setSaved(false);
    setError("");
    try {
      const res = await fetch("/api/admin/config", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        credentials: "include",
        body: JSON.stringify(config),
      });
      if (res.ok) {
        setSaved(true);
        setTimeout(() => setSaved(false), 2500);
      } else {
        setError("Error al guardar");
      }
    } catch {
      setError("Error de conexión");
    } finally {
      setSaving(false);
    }
  }

  const typeOptions: { value: BannerConfig["bannerType"]; label: string; color: string }[] = [
    { value: "info", label: "Info (azul)", color: "bg-blue-500/20 text-blue-300 border-blue-500/30" },
    { value: "warning", label: "Aviso (naranja)", color: "bg-amber-500/20 text-amber-300 border-amber-500/30" },
    { value: "success", label: "Éxito (verde)", color: "bg-green-500/20 text-green-300 border-green-500/30" },
  ];

  if (loading) {
    return <div className="h-40 bg-slate-800/40 rounded-xl animate-pulse" />;
  }

  return (
    <div className="space-y-5">
      <h2 className="text-white font-bold text-lg">Configuración del Banner</h2>

      <div className="bg-slate-800/40 border border-slate-700 rounded-2xl p-5 space-y-5">
        {/* Banner toggle */}
        <div className="flex items-center justify-between">
          <div>
            <p className="text-white font-medium text-sm">Banner activo</p>
            <p className="text-slate-400 text-xs mt-0.5">Muestra una barra informativa en el sitio</p>
          </div>
          <button
            onClick={() => setConfig((prev) => ({ ...prev, bannerEnabled: !prev.bannerEnabled }))}
            className={`relative w-12 h-6 rounded-full transition-colors duration-300 focus:outline-none ${
              config.bannerEnabled ? "bg-[#FFD400]" : "bg-slate-600"
            }`}
          >
            <span
              className={`absolute top-0.5 left-0.5 w-5 h-5 bg-white rounded-full shadow-md transition-transform duration-300 ${
                config.bannerEnabled ? "translate-x-6" : "translate-x-0"
              }`}
            />
          </button>
        </div>

        {/* Banner text */}
        <div>
          <label className="block text-white text-sm font-medium mb-1.5">Texto del banner</label>
          <textarea
            value={config.bannerText}
            onChange={(e) => setConfig((prev) => ({ ...prev, bannerText: e.target.value.slice(0, 200) }))}
            placeholder="Mensaje a mostrar en el banner…"
            rows={3}
            className="w-full bg-slate-900/60 border border-slate-700 rounded-xl px-4 py-3 text-white placeholder-slate-500 focus:outline-none focus:border-[#FFD400]/50 text-sm resize-none"
          />
          <p className="text-slate-500 text-xs mt-1 text-right">{config.bannerText.length}/200</p>
        </div>

        {/* Banner type */}
        <div>
          <label className="block text-white text-sm font-medium mb-2">Tipo de banner</label>
          <div className="flex gap-2 flex-wrap">
            {typeOptions.map((opt) => (
              <button
                key={opt.value}
                onClick={() => setConfig((prev) => ({ ...prev, bannerType: opt.value }))}
                className={`px-3 py-1.5 rounded-full text-xs font-semibold border transition-all ${
                  config.bannerType === opt.value
                    ? opt.color + " ring-2 ring-offset-1 ring-offset-slate-800 ring-current"
                    : "bg-slate-700/40 text-slate-400 border-slate-600 hover:border-slate-500"
                }`}
              >
                {opt.label}
              </button>
            ))}
          </div>
        </div>

        {/* Save button */}
        <button
          onClick={handleSave}
          disabled={saving}
          className="w-full bg-[#FFD400] hover:bg-[#FFE033] disabled:opacity-50 text-[#0F2438] font-black py-2.5 px-6 rounded-xl transition-all flex items-center justify-center gap-2 text-sm"
        >
          {saving ? <Loader2 className="w-4 h-4 animate-spin" /> : saved ? <CheckCircle className="w-4 h-4" /> : null}
          {saving ? "Guardando…" : saved ? "Guardado" : "Guardar cambios"}
        </button>

        {error && (
          <div className="flex items-center gap-2 text-red-400 text-sm bg-red-400/10 border border-red-400/20 rounded-lg px-3 py-2">
            <AlertTriangle className="w-4 h-4 flex-shrink-0" />
            {error}
          </div>
        )}
      </div>
    </div>
  );
}

// ── Dashboard ─────────────────────────────────────────────────────────────────
function Dashboard({ onLogout }: { onLogout: () => void }) {
  const [activeTab, setActiveTab] = useState<TabId>("inicio");
  const [maintenance, setMaintenance] = useState<boolean | null>(null);
  const [togglingMaint, setTogglingMaint] = useState(false);

  useEffect(() => {
    fetch("/api/admin/maintenance", { credentials: "include" })
      .then((r) => r.json())
      .then((d: { maintenance?: boolean }) => setMaintenance(d.maintenance ?? false))
      .catch(() => setMaintenance(false));
  }, []);

  async function toggleMaintenance() {
    if (maintenance === null) return;
    setTogglingMaint(true);
    try {
      const res = await fetch("/api/admin/maintenance", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ enabled: !maintenance }),
        credentials: "include",
      });
      if (res.ok) {
        const data = await res.json() as { maintenance?: boolean };
        setMaintenance(data.maintenance ?? !maintenance);
      }
    } catch { /* non-blocking */ }
    finally { setTogglingMaint(false); }
  }

  async function handleLogout() {
    await fetch("/api/admin/logout", { method: "POST", credentials: "include" });
    onLogout();
  }

  const tabs: { id: TabId; label: string; icon: React.ReactNode }[] = [
    { id: "inicio", label: "Inicio", icon: <LayoutDashboard className="w-4 h-4" /> },
    { id: "leads", label: "Leads", icon: <Users className="w-4 h-4" /> },
    { id: "salud", label: "Salud", icon: <Activity className="w-4 h-4" /> },
    { id: "config", label: "Config", icon: <Settings className="w-4 h-4" /> },
  ];

  return (
    <div className="min-h-screen bg-[#0F2438] flex flex-col p-4 sm:p-6">
      {/* Header */}
      <div className="flex items-center justify-between mb-6 max-w-2xl w-full mx-auto">
        <div className="flex items-center gap-3">
          <div className="w-10 h-10 rounded-full bg-[#FFD400]/10 border border-[#FFD400]/30 flex items-center justify-center">
            <Shield className="w-5 h-5 text-[#FFD400]" />
          </div>
          <div>
            <h1 className="text-white font-black text-lg leading-none">Panel Admin</h1>
            <p className="text-slate-500 text-xs">techbyflo.com</p>
          </div>
        </div>
        <div className="flex items-center gap-4">
          {/* Maintenance quick toggle */}
          <div className="flex items-center gap-2">
            <span className="text-slate-400 text-xs hidden sm:block">Mant.</span>
            <button
              onClick={toggleMaintenance}
              disabled={togglingMaint || maintenance === null}
              title="Modo mantenimiento"
              className={`relative w-10 h-5 rounded-full transition-colors duration-300 focus:outline-none disabled:opacity-50 ${
                maintenance ? "bg-red-500" : "bg-slate-600"
              }`}
            >
              <span
                className={`absolute top-0.5 left-0.5 w-4 h-4 bg-white rounded-full shadow-md transition-transform duration-300 flex items-center justify-center ${
                  maintenance ? "translate-x-5" : "translate-x-0"
                }`}
              >
                {togglingMaint ? (
                  <Loader2 className="w-2.5 h-2.5 text-slate-400 animate-spin" />
                ) : (
                  <Power className={`w-2.5 h-2.5 ${maintenance ? "text-red-500" : "text-slate-400"}`} />
                )}
              </span>
            </button>
          </div>
          <button
            onClick={handleLogout}
            className="flex items-center gap-1.5 text-slate-400 hover:text-white text-sm transition-colors"
          >
            <LogOut className="w-4 h-4" />
            <span className="hidden sm:block">Salir</span>
          </button>
        </div>
      </div>

      {/* Tab navigation */}
      <div className="max-w-2xl w-full mx-auto mb-5">
        <div className="flex gap-1 bg-slate-800/40 border border-slate-700 rounded-2xl p-1">
          {tabs.map((tab) => (
            <button
              key={tab.id}
              onClick={() => setActiveTab(tab.id)}
              className={`flex-1 flex items-center justify-center gap-1.5 px-3 py-2 rounded-xl text-sm font-medium transition-all ${
                activeTab === tab.id
                  ? "bg-[#FFD400] text-[#0F2438]"
                  : "text-slate-400 hover:text-white"
              }`}
            >
              {tab.icon}
              <span className="hidden sm:block">{tab.label}</span>
            </button>
          ))}
        </div>
      </div>

      {/* Tab content */}
      <div className="max-w-2xl w-full mx-auto flex-1">
        <div className="bg-slate-800/20 border border-slate-700 rounded-2xl p-5">
          {activeTab === "inicio" && <TabInicio />}
          {activeTab === "leads" && <TabLeads />}
          {activeTab === "salud" && <TabSalud />}
          {activeTab === "config" && <TabConfig />}
        </div>
      </div>

      <p className="text-slate-600 text-xs text-center mt-4 max-w-2xl mx-auto">
        Los cambios son instantáneos · Sesión válida 24h
      </p>
    </div>
  );
}

// ── Main Admin page ───────────────────────────────────────────────────────────
export default function AdminPage() {
  const [authenticated, setAuthenticated] = useState<boolean | null>(null);

  useEffect(() => {
    fetch("/api/admin/maintenance", { credentials: "include" })
      .then((r) => setAuthenticated(r.status !== 401))
      .catch(() => setAuthenticated(false));
  }, []);

  if (authenticated === null) {
    return (
      <div className="min-h-screen bg-[#0F2438] flex items-center justify-center">
        <Loader2 className="w-8 h-8 text-[#FFD400] animate-spin" />
      </div>
    );
  }

  if (!authenticated) {
    return <LoginForm onLogin={() => setAuthenticated(true)} />;
  }

  return <Dashboard onLogout={() => setAuthenticated(false)} />;
}

