import { useState, useEffect } from "react";
import { Link, useLocation } from "wouter";
import { AlertTriangle, ArrowLeft, X, Info, CheckCircle } from "lucide-react";
import { cn } from "@/lib/utils";

interface BannerData {
  enabled: boolean;
  text: string;
  type: "info" | "warning" | "success";
}

function SiteBanner() {
  const [banner, setBanner] = useState<BannerData | null>(null);
  const [dismissed, setDismissed] = useState(false);

  useEffect(() => {
    fetch("/api/banner")
      .then((r) => r.json())
      .then((d: BannerData) => setBanner(d))
      .catch(() => {});
  }, []);

  if (!banner || !banner.enabled || dismissed || !banner.text) return null;

  const styles = {
    info: { bar: "bg-blue-600 border-blue-500", text: "text-white", icon: <Info className="w-4 h-4 shrink-0" /> },
    warning: { bar: "bg-amber-500 border-amber-400", text: "text-[#0F2438]", icon: <AlertTriangle className="w-4 h-4 shrink-0" /> },
    success: { bar: "bg-green-600 border-green-500", text: "text-white", icon: <CheckCircle className="w-4 h-4 shrink-0" /> },
  }[banner.type];

  return (
    <div className={`w-full border-b ${styles.bar} px-4 py-2.5 flex items-center justify-between gap-3`}>
      <div className={`flex items-center gap-2 ${styles.text} text-sm font-medium`}>
        {styles.icon}
        <span>{banner.text}</span>
      </div>
      <button
        onClick={() => setDismissed(true)}
        className={`${styles.text} opacity-70 hover:opacity-100 transition-opacity flex-shrink-0`}
        aria-label="Cerrar aviso"
      >
        <X className="w-4 h-4" />
      </button>
    </div>
  );
}

export default function Layout({ children, className }: { children: React.ReactNode, className?: string }) {
  const [location] = useLocation();
  const isHome = location === "/";

  return (
    <div className="min-h-screen bg-[#0F2438] text-white flex flex-col">
      <SiteBanner />
    <div className="flex flex-col items-center py-8 px-4 sm:px-6 lg:px-8 flex-1">
      <div className={cn("w-full max-w-md mx-auto space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-700", className)}>

